import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assume the function to test is exported from './handler'
import { handleSubmit } from './handler';

// Mock any external dependencies that handleSubmit might use
vi.mock('./api', () => ({
  postNote: vi.fn(),
}));

describe('handleSubmit', () => {
  const mockEvent = (preventDefault: boolean = true, target: any = {}) => ({
    preventDefault: vi.fn(),
    target,
  });

  beforeEach(() => {
    // reset mocks before each test
    vi.clearAllMocks();
  });

  it('should handle happy path', async () => {
    const event = mockEvent();
    const mockTarget = {
      noteTitle: { value: 'Test Title' },
      noteContent: { value: 'Test Content' },
    };
    const mockPreventDefault = vi.fn();
    const mockEventWithTarget = {
      preventDefault: mockPreventDefault,
      target: mockTarget,
    };

    // Import the mocked API function
    const { postNote } = await import('./api');
    postNote.mockResolvedValueOnce({ id: 1 });

    await handleSubmit(mockEventWithTarget as any);

    expect(mockPreventDefault).toHaveBeenCalled();
    expect(postNote).toHaveBeenCalledWith({
      title: 'Test Title',
      content: 'Test Content',
    });
  });

  it('should handle edge case with empty strings', async () => {
    const mockTarget = {
      noteTitle: { value: '' },
      noteContent: { value: '' },
    };
    const mockPreventDefault = vi.fn();
    const mockEvent = {
      preventDefault: mockPreventDefault,
      target: mockTarget,
    };

    const { postNote } = await import('./api');
    postNote.mockResolvedValueOnce({ id: 2 });

    await handleSubmit(mockEvent as any);

    expect(mockPreventDefault).toHaveBeenCalled();
    expect(postNote).toHaveBeenCalledWith({
      title: '',
      content: '',
    });
  });

  it('should handle null/empty event or target', async () => {
    const mockPreventDefault = vi.fn();
    const eventWithNullTarget = {
      preventDefault: mockPreventDefault,
      target: null,
    };

    // Import the mocked API function
    const { postNote } = await import('./api');
    postNote.mockResolvedValueOnce({ id: 3 });

    await expect(handleSubmit(eventWithNullTarget as any)).resolves.not.toThrow();

    expect(mockPreventDefault).toHaveBeenCalled();
    expect(postNote).toHaveBeenCalledWith({
      title: '',
      content: '',
    });
  });
});